#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long x,y,xr,yr,D;
        scanf("%lld %lld %lld %lld %lld", &x, &y, &xr, &yr, &D);
        long long daysFood = x / xr;
        long long daysWater = y / yr;
        long long survivable = daysFood < daysWater ? daysFood : daysWater;
        if(survivable >= D) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

